mapper.select:
SELECT COUNT(1)
FROM COMTNEMPLYRINFO
WHERE EMPLYR_ID = #{value}

SELECT * FROM ( SELECT rownum AS rn, TB.* FROM ( SELECT ESNTL_ID AS uniqId, 'USR03' AS userTy, EMPLYR_ID AS emplyrId, USER_NM AS emplyrNm, EMAIL_ADRES AS emailAdres, AREA_NO AS areaNo, HOUSE_MIDDLE_TELNO AS homemiddleTelno, HOUSE_END_TELNO AS homeendTelno, MBTLNUM AS moblphonNo, GROUP_ID AS groupId, EMPLYR_STTUS_CODE AS emplyrSttusCode, TO_CHAR(SBSCRB_DE, 'YYYY.MM.DD HH24:MI:SS') AS sbscrbDe, ORGNZT_ID AS orgnztId, OFCPS_NM AS ofcpsNm, OFFM_TELNO AS offmTelno, EMPL_NO AS emplNo, LOCK_AT AS lockAt FROM COMTNEMPLYRINFO WHERE 1 = 1
AND EMPLYR_STTUS_CODE = #{sbscrbSttus}
AND EMPLYR_ID LIKE '%' || #{searchKeyword} || '%'
AND USER_NM LIKE '%' || #{searchKeyword} || '%'
AND ( EMPLYR_ID LIKE '%' || #{searchKeyword} || '%' OR USER_NM LIKE '%' || #{searchKeyword} || '%' OR EMAIL_ADRES LIKE '%' || #{searchKeyword} || '%' OR ORGNZT_ID LIKE '%' || #{searchKeyword} || '%' )
ORDER BY SBSCRB_DE DESC ) TB ) Z WHERE rn BETWEEN #{firstIndex} + 1 AND #{firstIndex} + #{recordCountPerPage}

SELECT PASSWORD AS password
FROM COMTNEMPLYRINFO
WHERE ESNTL_ID = #{uniqId}
